mapper.select:
SELECT id, last_success_at, last_trade_date, last_quote_time, last_error, updated_at
FROM social.carbon_market_sync_state
WHERE id = #{id}

mapper.update:
UPDATE social.carbon_market_sync_state
SET
  last_error = #{lastError, jdbcType=VARCHAR},
  updated_at = #{updatedAt, jdbcType=TIMESTAMP_WITH_TIMEZONE}
WHERE id = #{id}
